DROP DATABASE IF EXISTS pcshop;
CREATE DATABASE IF NOT EXISTS pcshop DEFAULT CHARACTER SET utf8mb4 COLLATE utf8mb4_hungarian_ci;
USE pcshop;
CREATE TABLE users (userID INT AUTO_INCREMENT PRIMARY KEY, nev VARCHAR(100) NOT NULL, lakcim VARCHAR(255), telefon VARCHAR(30), email VARCHAR(100) UNIQUE NOT NULL, password VARCHAR(255) NOT NULL, status ENUM('admin', 'vevo', 'dolgozo') DEFAULT 'vevo', ban BOOLEAN DEFAULT 0);
CREATE TABLE payments (fizID INT AUTO_INCREMENT PRIMARY KEY, mivel VARCHAR(50) NOT NULL, fizetve BOOLEAN DEFAULT 0, datum DATETIME DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE categories (kID INT AUTO_INCREMENT PRIMARY KEY, kategoriaNev VARCHAR(100) NOT NULL);
CREATE TABLE orders (orderID INT AUTO_INCREMENT PRIMARY KEY, userID INT NOT NULL, fizID INT, datum DATETIME DEFAULT CURRENT_TIMESTAMP, allapot VARCHAR(50) DEFAULT 'Feldolgozás alatt', FOREIGN KEY (userID) REFERENCES users(userID), FOREIGN KEY (fizID) REFERENCES payments(fizID));
CREATE TABLE products (pID INT AUTO_INCREMENT PRIMARY KEY, kID INT NOT NULL, nev VARCHAR(150) NOT NULL, ar INT NOT NULL, leiras TEXT, FOREIGN KEY (kID) REFERENCES categories(kID));
CREATE TABLE order_items (orderItemID INT AUTO_INCREMENT PRIMARY KEY, orderID INT NOT NULL, pID INT NOT NULL, darab INT NOT NULL, ar_akkor INT NOT NULL, FOREIGN KEY (orderID) REFERENCES orders(orderID), FOREIGN KEY (pID) REFERENCES products(pID));
CREATE TABLE cart_items (userID INT NOT NULL, pID INT NOT NULL, darab INT NOT NULL DEFAULT 1, PRIMARY KEY (userID, pID), FOREIGN KEY (userID) REFERENCES users(userID) ON DELETE CASCADE, FOREIGN KEY (pID) REFERENCES products(pID));
CREATE TABLE product_attributes (attrID INT AUTO_INCREMENT PRIMARY KEY, pID INT NOT NULL, paramnev VARCHAR(100) NOT NULL, ertek VARCHAR(255) NOT NULL, FOREIGN KEY (pID) REFERENCES products(pID));
CREATE TABLE stock (pID INT PRIMARY KEY, db INT NOT NULL, FOREIGN KEY (pID) REFERENCES products(pID));
CREATE TABLE product_images (imageID INT AUTO_INCREMENT PRIMARY KEY, pID INT NOT NULL, image_data LONGTEXT NOT NULL, is_primary BOOLEAN DEFAULT 0, sorrend INT DEFAULT 0, FOREIGN KEY (pID) REFERENCES products(pID) ON DELETE CASCADE);

